DataSource.SQL:
DECLARE @LastTreeIdent VARCHAR(900)	=	(SELECT COALESCE(@ITSMCategoryLevel5Ident, @ITSMCategoryLevel4Ident, @ITSMCategoryLevel3Ident, @ITSMCategoryLevel2Ident, @ITSMCompanyIdent))

;WITH BreakdownHierarchy AS (
	SELECT
		reqBreSub.BreakdownFolderTreeIdent,
		folTreBre.Ident,
		folTreBre.Level,
		folTreBre.ParentFolderTreeID
	FROM usr.ITSMRequestBreakdownSubForm AS reqBreSub
	INNER JOIN dbo.FolderTreeView AS folTreBre ON folTreBre.Ident = reqBreSub.BreakdownFolderTreeIdent
	WHERE reqBreSub.TableID = @ID AND reqBreSub.FormIdent = 'ITSMRequest' AND reqBreSub.State != @DeletedState

	UNION ALL

	SELECT
		bh.BreakdownFolderTreeIdent,
		parent.Ident,
		parent.Level,
		parent.ParentFolderTreeID
	FROM BreakdownHierarchy AS bh
	INNER JOIN dbo.FolderTree AS parent ON parent.ID = bh.ParentFolderTreeID
)

SELECT DISTINCT
	@Subject AS Subject,
	MAX(CASE WHEN bh.Level = 1 THEN bh.Ident END) AS ITSMCompanyIdent,
	MAX(CASE WHEN bh.Level = 2 THEN bh.Ident END) AS ITSMCategoryLevel2Ident,
	MAX(CASE WHEN bh.Level = 3 THEN bh.Ident END) AS ITSMCategoryLevel3Ident,
	MAX(CASE WHEN bh.Level = 4 THEN bh.Ident END) AS ITSMCategoryLevel4Ident,
	MAX(CASE WHEN bh.Level = 5 THEN bh.Ident END) AS ITSMCategoryLevel5Ident,
	@ReporterAccountID AS ReporterAccountID,
	@ReporterEmail AS ReporterEmail,
	@ReporterPhone AS ReporterPhone,
	@ID AS ParentTableID,
	@Description AS Description,
	@UserName AS UserName,
	@CertificateType AS CertificateType,
	@RequestType AS RequestType,
	@ConsumerName AS ConsumerName,
	@ValidityPeriod AS ValidityPeriod,
	@OriginalHWIMNumber AS OriginalHWIMNumber,
	@Justification AS Justification,
	@RequestCategory AS RequestCategory,
	@Renewal AS Renewal,
	@Failure AS Failure,
	@Employee AS Employee,
	@Requirement AS Requirement,
	@CompletionDate AS CompletionDate,
	@Attachment AS Attachment,
	@Login AS Login,
	@Permission AS Permission,
	@SerialNumber AS SerialNumber,
	@ExpirationDate AS ExpirationDate,
	@Environment AS Environment,
	@CommonName AS CommonName,
	@Email AS Email,
	@Organization AS Organization,
	@SecondOrganization AS SecondOrganization,
	@Locality AS Locality,
	@StateField AS StateField,
	@Country AS Country,
	@SANAttribute AS SANAttribute,
	@ServerName AS ServerName,
	@IPAddress AS IPAddress,
	@Zone AS Zone,
	@vdom AS vdom,
	@Transport AS Transport,
	@Port AS Port,
	@RevocationRequestDescription AS RevocationRequestDescription,
	@ITSMEntryMethodTypeGuid AS ITSMEntryMethodTypeGuid
FROM BreakdownHierarchy AS bh
GROUP BY bh.BreakdownFolderTreeIdent

DECLARE @LastFolderTree VARCHAR(900);
DECLARE @NewApproveRoundGUID uniqueidentifier = ( SELECT ActualApproveRoundGuid FROM usr.ITSMRequest WHERE ID = @ID )
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT @ID AS TableID, @FormIdent AS FormIdent, appsf.ApproveOrder AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @NewApproveRoundGUID AS ApproveRoundGUID FROM usr.ITSMApproval AS appsf WHERE ApproveRoundGUID = @OldActualApproveRoundGuid AND appsf.TableID = @ID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState

DECLARE @LastFolderTree VARCHAR(900);
DECLARE @NewApproveRoundGUID uniqueidentifier = ( SELECT ActualApproveRoundGuid FROM usr.ITSMRequest WHERE ID = @ID )
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT @ID AS TableID, @FormIdent AS FormIdent, appsf.ApproveOrder AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @NewApproveRoundGUID AS ApproveRoundGUID FROM usr.ITSMApproval AS appsf WHERE ApproveRoundGUID = @OldActualApproveRoundGuid AND appsf.TableID = @ID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState

DECLARE @LastFolderTree VARCHAR(900);
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT (ISNULL(@LastApproveOrder,0) + appsf.ApproveOrder) AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @ActualApproveRoundGuid AS ApproveRoundGUID FROM usr.ITSMApproveSubForm AS appsf INNER JOIN usr.ITSMApproveSetting AS appSet ON appSet.ID = appsf.TableID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState INNER JOIN dbo.FolderTree AS folTre ON folTre.Ident = @LastFolderTree INNER JOIN dbo.Folder AS fol ON fol.ID = folTre.FolderID AND fol.FormIdent = @CategoryFormIdent INNER JOIN usr.ITSMCategory AS cat ON cat.ID = fol.TableID AND cat.ITSMApproveSettingID = appSet.ID

DECLARE @PermissionIDs dbo.ListNVarchar100Type;
INSERT INTO @PermissionIDs VALUES ('ITSMSpecialist'), ('ITSMOperator');

SELECT TOP(1)
		itsGagvftap.GroupID
FROM usr.ITSM_GetAllowedGroupByFolderTreeAndPermission(
		COALESCE(@ITSMCategoryLevel5Ident, @ITSMCategoryLevel4Ident, @ITSMCategoryLevel3Ident, @ITSMCategoryLevel2Ident, @ITSMCompanyIdent),
		@PermissionIDs
) AS itsGagvftap
INNER JOIN dbo.GroupAccount AS gra ON gra.GroupID = itsGagvftap.GroupID AND gra.AccountID = @UserID

